class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string result;
        while (a > 0 || b > 0) {
            if (a >= b && a > 0 && (result.size() < 2 || result.back() != 'a')) {
                result += 'a';
                a--;
            } else if (b > 0 && (result.size() < 2 || result.back() != 'b')) {
                result += 'b';
                b--;
            } else if (a > 0) {
                result += 'a';
                a--;
            } else {
                result += 'b';
                b--;
            }
        }
        return result;
    }
};
```
